import React, { useState, useEffect } from 'react';
import AsyncStorage from '@react-native-community/async-storage';

const AuthScreen = ({ navigation }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [userData, setUserData] = useState(null);
  const [authToken, setAuthToken] = useState(null);

  useEffect(() => {
    const loadAsyncStorage = async () => {
      const userDataJson = await AsyncStorage.getItem('userData');
      const authTokenJson = await AsyncStorage.getItem('authToken');

      if (userDataJson !== null && authTokenJson !== null) {
        setUserData(JSON.parse(userDataJson));
        setAuthToken(JSON.parse(authTokenJson));
      }
    };

    loadAsyncStorage();
  }, []);

  const login = async () => {
    // Simulate actual authentication logic here
    const response = await fetch('https://your-api-url/login', {
      method: 'POST',
      headers: {
        'Accept': 'application/json',
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ username, password }),
    });

    const responseJson = await response.json();

    if (response.ok) {
      // Save user data and auth token to AsyncStorage
      await AsyncStorage.setItem('userData', JSON.stringify(responseJson.user));
      await AsyncStorage.setItem('authToken', JSON.stringify(responseJson.token));

      // Navigate to the main screen after successful login
      navigation.navigate('Main');
    }
  };

  return (
    <View>
      {/* Render login form here */}
      <Button title="Login" onPress={login} />
    </View>
  );
};

export default AuthScreen;